Unpatched ClusPoolReadRegistrationKeys (0x1C000FB28):
    v4 = nullptr;
    for (i = 2056; ; i = keycount + 8) {
        buf = ExAllocatePoolWithTag((POOL_TYPE)512, i, 0x30536443);  // NOT zeroed
        if (v4) ExFreePoolWithTag(v4, 0);   // free previous
        v4 = buf;
        if (!buf) goto trace_exit;
        rc = ClusPoolSendIoctl3(DeviceObject, 0x2D5018, ..., buf, i, &outlen);
        if (rc < 0) goto trace_exit;        // v4 (== buf) freed at exit
        keycount = be32(buf[4..7]);
        if (keycount + 8 <= i) break;       // enough -> validate below
        if (keycount + 8 > 0x8000) goto trace_exit;
    }
    if (outlen >= 8 && be32(buf[4..7]) <= outlen - 8) { v4 = nullptr; *a2 = buf; rc = 0; }
trace_exit:
    if (v4) ExFreePoolWithTag(v4, 0);
    return rc;

